        user = USERS[user_id]
        return {
            "role": user["role"],
            "subscription_level": user["subscription_level"]
        }
    return None

def can_access_content(user_id, content_id):
    user_info = get_user_info(user_id)
    if not user_info:
        return False

    if content_id not in CONTENT:
